exercises.solution:
import numpy as np

def qpe_resources(precision_bits, confidence_percent):
    epsilon = 1 - confidence_percent/100
    if epsilon <= 0:
        epsilon = 0.0001
    extra = int(np.ceil(np.log2(2 + 1/(2*epsilon))))
    return precision_bits + extra

for prec in [8, 16, 32]:
    for conf in [90, 99, 99.9]:
        q = qpe_resources(prec, conf)
        print(f'{prec}-bit @ {conf}%: {q} qubits')

