exercises.solution:
def shor_estimate(rsa_bits):
    qubits = 3 * rsa_bits
    gates = rsa_bits ** 3  # Rough estimate
    return {'qubits': qubits, 'gates_millions': gates // 1000000}

for bits in [512, 1024, 2048, 4096]:
    r = shor_estimate(bits)
    print(f'RSA-{bits}: ~{r["qubits"]} qubits, ~{r["gates_millions"]}M gates')
